#!/bin/bash
# Platform run.sh for H007_candidate_aware_xattn.
# CLAUDE.md §17.2 one-mutation: original_baseline anchor 와 byte-identical envelope,
# `--use_candidate_summary_token` flag 만 추가. 신규 클래스 CandidateSummaryToken
# (Pre-LN multi-head cross-attention) per-domain 적용. candidate token = item_ns +
# item_dense_tok mean pool. seq 시작에 prepend → 다운스트림 자동 candidate-aware.
# §17.4 rotation 추가 충족 (target_attention).
# §18 inference 인프라 룰 inherit from original_baseline.
# Generated by skills/_helpers/build_cloud_package.py — do not hand-edit on platform.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
export PYTHONPATH="${SCRIPT_DIR}:${PYTHONPATH:-}"

# ---------------------------------------------------------------------------
# Platform must set TRAIN_DATA_PATH and TRAIN_CKPT_PATH. Other paths derive.
# ---------------------------------------------------------------------------
: "${TRAIN_DATA_PATH:?TRAIN_DATA_PATH not set by platform}"
: "${TRAIN_CKPT_PATH:?TRAIN_CKPT_PATH not set by platform}"
: "${TRAIN_LOG_PATH:=${TRAIN_CKPT_PATH}/logs}"
: "${TRAIN_TF_EVENTS_PATH:=${TRAIN_CKPT_PATH}/tf_events}"
: "${TRAIN_WORK_PATH:=${TRAIN_CKPT_PATH}/work}"
mkdir -p "${TRAIN_CKPT_PATH}" "${TRAIN_LOG_PATH}" "${TRAIN_TF_EVENTS_PATH}" "${TRAIN_WORK_PATH}"
export TRAIN_LOG_PATH TRAIN_TF_EVENTS_PATH

echo "[run.sh] DATA=${TRAIN_DATA_PATH}"
echo "[run.sh] CKPT=${TRAIN_CKPT_PATH}"
echo "[run.sh] mode=candidate-aware-xattn-smoke + leak-fix (anchor envelope + use_candidate_summary_token)"

# ---------------------------------------------------------------------------
# Train (anchor envelope + CandidateSummaryToken per domain).
# Diff vs original_baseline/run.sh:
#   --use_candidate_summary_token    NEW: candidate-aware cross-attention pooling
#                                    per domain. Prepends candidate-attended summary
#                                    token to each sequence (L → L+1 per domain).
# ---------------------------------------------------------------------------
python3 -u "${SCRIPT_DIR}/train.py" \
    --num_epochs 1 \
    --patience 5 \
    --seed 42 \
    --ns_tokenizer_type rankmixer \
    --user_ns_tokens 5 \
    --item_ns_tokens 2 \
    --num_queries 2 \
    --ns_groups_json "" \
    --emb_skip_threshold 1000000 \
    --num_workers 2 \
    --buffer_batches 4 \
    --train_ratio 0.05 \
    --seq_max_lens "seq_a:64,seq_b:64,seq_c:128,seq_d:128" \
    --use_label_time_split \
    --oof_user_ratio 0.1 \
    --split_seed 42 \
    --use_candidate_summary_token \
    "$@"

echo "[run.sh] training complete (candidate-aware-xattn-smoke); metrics at ${TRAIN_CKPT_PATH}/metrics.json"
